<div class="check-row"><input type="checkbox" id="addMeta" onchange="gen()"><label for="addMeta">Add pagination meta</label></div>
<div class="check-row"><input type="checkbox" id="addTimestamp" checked onchange="gen()"><label for="addTimestamp">Add timestamps</label></div>
