<style>
  :root {
    --bg: #0d1117;
    --surface: #161b22;
    --border: #30363d;
    --text: #e6edf3;
    --text2: #8b949e;
    --accent: #58a6ff;
    --green: #3fb950;
    --red: #f85149;
    --yellow: #d29922;
    --blue: #58a6ff;
    --orange: #e3b341;
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
    font-size: 14px;
    line-height: 1.5;
    min-height: 100vh;
  }

  a { color: var(--accent); text-decoration: none; }
  a:hover { text-decoration: underline; }

  .top-bar {
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    padding: 10px 20px;
    display: flex;
    align-items: center;
    gap: 16px;
  }

  .top-bar .back-link {
    color: var(--text2);
    font-size: 13px;
    white-space: nowrap;
  }

  .top-bar .back-link:hover { color: var(--accent); }

  .top-bar h1 {
    font-size: 16px;
    font-weight: 600;
    color: var(--text);
  }

  .layout {
    display: grid;
    grid-template-columns: 260px 1fr 1fr;
    height: calc(100vh - 45px);
    overflow: hidden;
  }

  /* Sidebar */
  .sidebar {
    background: var(--surface);
    border-right: 1px solid var(--border);
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }

  .sidebar-section {
    padding: 12px;
    border-bottom: 1px solid var(--border);
  }

  .sidebar-section h3 {
    font-size: 11px;
    font-weight: 600;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.08em;
    margin-bottom: 8px;
  }

  .preset-btn {
    display: block;
    width: 100%;
    background: none;
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text);
    padding: 7px 10px;
    margin-bottom: 4px;
    cursor: pointer;
    text-align: left;
    font-size: 12px;
    transition: all 0.15s;
  }

  .preset-btn:hover {
    background: rgba(88, 166, 255, 0.08);
    border-color: var(--accent);
  }

  .preset-btn .preset-method {
    display: inline-block;
    font-size: 10px;
    font-weight: 700;
    padding: 1px 5px;
    border-radius: 3px;
    margin-right: 6px;
    color: #fff;
  }

  .preset-btn .preset-label {
    color: var(--text2);
    font-size: 11px;
  }

  .history-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
  }

  .history-item {
    display: flex;
    align-items: flex-start;
    gap: 6px;
    padding: 7px 8px;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.1s;
    margin-bottom: 2px;
  }

  .history-item:hover { background: rgba(255,255,255,0.05); }

  .history-item .hist-method {
    font-size: 10px;
    font-weight: 700;
    padding: 1px 5px;
    border-radius: 3px;
    color: #fff;
    flex-shrink: 0;
    margin-top: 1px;
  }

  .history-item .hist-info {
    overflow: hidden;
  }

  .history-item .hist-url {
    font-size: 12px;
    color: var(--text);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .history-item .hist-meta {
    font-size: 11px;
    color: var(--text2);
    margin-top: 1px;
  }

  .history-empty {
    padding: 12px 8px;
    color: var(--text2);
    font-size: 12px;
    text-align: center;
  }

  /* Request panel */
  .request-panel {
    display: flex;
    flex-direction: column;
    overflow: hidden;
    border-right: 1px solid var(--border);
  }

  .url-bar {
    display: flex;
    gap: 8px;
    padding: 12px;
    border-bottom: 1px solid var(--border);
    background: var(--surface);
  }

  .method-select {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    color: var(--text);
    padding: 8px 10px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    min-width: 96px;
    outline: none;
    transition: border-color 0.15s;
  }

  .method-select:focus { border-color: var(--accent); }

  .url-input {
    flex: 1;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    color: var(--text);
    padding: 8px 12px;
    font-size: 13px;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    outline: none;
    transition: border-color 0.15s;
  }

  .url-input:focus { border-color: var(--accent); }
  .url-input::placeholder { color: var(--text2); }

  .send-btn {
    background: var(--accent);
    border: none;
    border-radius: 8px;
    color: #0d1117;
    padding: 8px 18px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 7px;
    white-space: nowrap;
    transition: opacity 0.15s;
  }

  .send-btn:hover { opacity: 0.85; }
  .send-btn:disabled { opacity: 0.5; cursor: not-allowed; }

  .spinner {
    width: 14px;
    height: 14px;
    border: 2px solid rgba(13,17,23,0.3);
    border-top-color: #0d1117;
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
    display: none;
  }

  .send-btn.loading .spinner { display: block; }
  .send-btn.loading .btn-label { display: none; }

  @keyframes spin { to { transform: rotate(360deg); } }

  .tabs {
    display: flex;
    gap: 2px;
    padding: 8px 12px 0;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
  }

  .tab-btn {
    background: none;
    border: none;
    border-bottom: 2px solid transparent;
    color: var(--text2);
    padding: 6px 12px;
    font-size: 13px;
    cursor: pointer;
    transition: all 0.15s;
    white-space: nowrap;
  }

  .tab-btn:hover { color: var(--text); }
  .tab-btn.active { color: var(--accent); border-bottom-color: var(--accent); }

  .tab-badge {
    background: var(--accent);
    color: #0d1117;
    font-size: 10px;
    font-weight: 700;
    padding: 0 5px;
    border-radius: 10px;
    margin-left: 4px;
  }

  .tab-content {
    flex: 1;
    overflow-y: auto;
    padding: 12px;
  }

  .tab-pane { display: none; }
  .tab-pane.active { display: block; }

  .kv-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 8px;
  }

  .kv-table th {
    text-align: left;
    font-size: 11px;
    font-weight: 600;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    padding: 4px 6px;
    border-bottom: 1px solid var(--border);
  }

  .kv-table td {
    padding: 4px 4px;
  }

  .kv-input {
    width: 100%;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text);
    padding: 6px 8px;
    font-size: 12px;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    outline: none;
    transition: border-color 0.15s;
  }

  .kv-input:focus { border-color: var(--accent); }
  .kv-input::placeholder { color: var(--text2); }

  .kv-remove-btn {
    background: none;
    border: none;
    color: var(--text2);
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 14px;
    line-height: 1;
    transition: all 0.1s;
  }

  .kv-remove-btn:hover { color: var(--red); background: rgba(248,81,73,0.1); }

  .add-row-btn {
    background: none;
    border: 1px dashed var(--border);
    border-radius: 6px;
    color: var(--text2);
    padding: 6px 12px;
    font-size: 12px;
    cursor: pointer;
    width: 100%;
    transition: all 0.15s;
  }

  .add-row-btn:hover { border-color: var(--accent); color: var(--accent); }

  .body-textarea {
    width: 100%;
    height: calc(100% - 30px);
    min-height: 200px;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    color: var(--text);
    padding: 10px 12px;
    font-size: 12px;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    resize: vertical;
    outline: none;
    line-height: 1.6;
    tab-size: 2;
    transition: border-color 0.15s;
  }

  .body-textarea:focus { border-color: var(--accent); }
  .body-textarea::placeholder { color: var(--text2); }

  .body-tools {
    display: flex;
    gap: 6px;
    margin-bottom: 8px;
    align-items: center;
  }

  .body-tool-btn {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text2);
    padding: 4px 10px;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.15s;
  }

  .body-tool-btn:hover { color: var(--text); border-color: var(--text2); }

  .cors-note {
    background: rgba(210,153,34,0.1);
    border: 1px solid rgba(210,153,34,0.3);
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 12px;
    color: var(--yellow);
    margin-top: 8px;
  }

  /* Response panel */
  .response-panel {
    display: flex;
    flex-direction: column;
    overflow: hidden;
  }

  .response-header {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 12px;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    flex-wrap: wrap;
  }

  .response-header h2 {
    font-size: 13px;
    font-weight: 600;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.06em;
  }

  .status-badge {
    font-size: 13px;
    font-weight: 700;
    padding: 3px 10px;
    border-radius: 20px;
  }

  .status-2xx { background: rgba(63,185,80,0.15); color: var(--green); }
  .status-3xx { background: rgba(88,166,255,0.15); color: var(--blue); }
  .status-4xx { background: rgba(210,153,34,0.15); color: var(--yellow); }
  .status-5xx { background: rgba(248,81,73,0.15); color: var(--red); }

  .stat-chip {
    display: flex;
    align-items: center;
    gap: 4px;
    font-size: 12px;
    color: var(--text2);
  }

  .stat-chip .stat-val {
    color: var(--text);
    font-weight: 500;
  }

  .copy-btn {
    margin-left: auto;
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    color: var(--text2);
    padding: 4px 10px;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.15s;
    display: flex;
    align-items: center;
    gap: 5px;
  }

  .copy-btn:hover { color: var(--text); border-color: var(--text2); }
  .copy-btn.copied { color: var(--green); border-color: var(--green); }

  .response-body-area {
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
  }

  .response-tabs {
    display: flex;
    gap: 2px;
    padding: 8px 12px 0;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
  }

  .resp-tab-btn {
    background: none;
    border: none;
    border-bottom: 2px solid transparent;
    color: var(--text2);
    padding: 6px 12px;
    font-size: 13px;
    cursor: pointer;
    transition: all 0.15s;
  }

  .resp-tab-btn:hover { color: var(--text); }
  .resp-tab-btn.active { color: var(--accent); border-bottom-color: var(--accent); }

  .response-content {
    flex: 1;
    overflow-y: auto;
    padding: 12px;
  }

  .empty-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100%;
    min-height: 200px;
    color: var(--text2);
    gap: 8px;
  }

  .empty-state .empty-icon {
    font-size: 32px;
    opacity: 0.4;
  }

  .empty-state p {
    font-size: 13px;
  }

  pre.json-view {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 12px;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 12px;
    line-height: 1.7;
    overflow-x: auto;
    white-space: pre-wrap;
    word-break: break-all;
  }

  .json-key { color: #79c0ff; }
  .json-string { color: #a5d6ff; }
  .json-number { color: #f2cc60; }
  .json-bool { color: #ff7b72; }
  .json-null { color: var(--text2); font-style: italic; }

  .headers-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 12px;
  }

  .headers-table th {
    text-align: left;
    color: var(--text2);
    font-weight: 600;
    padding: 6px 8px;
    border-bottom: 1px solid var(--border);
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 0.06em;
  }

  .headers-table td {
    padding: 5px 8px;
    border-bottom: 1px solid rgba(48,54,61,0.5);
    vertical-align: top;
  }

  .headers-table td:first-child {
    color: var(--accent);
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    white-space: nowrap;
    width: 40%;
  }

  .headers-table td:last-child {
    color: var(--text);
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    word-break: break-all;
  }

  /* Method colors */
  .m-get    { background: #1f6feb; }
  .m-post   { background: #238636; }
  .m-put    { background: #9e6a03; }
  .m-patch  { background: #6e40c9; }
  .m-delete { background: #b62324; }
  .m-head   { background: #1f6feb; }
  .m-options { background: #57606a; }

  /* Scrollbars */
